	.clk62(clk62),
	.cfg_clk(cfg_clk),
	.phy_rstn(phy_rstn),
	.clk_locked(clk_locked),
	.si570(si570),
	.SCLK(SCLK),
	.CSB(CSB),
	.MOSI(MOSI),
	.MISO(MISO),
	.mmc_int(mmc_int),
	.boot_clk(boot_clk),
	.boot_cs(boot_cs),
	.boot_mosi(boot_mosi),
	.boot_miso(boot_miso),
	.cfg_d02(cfg_d02),
	.twi_scl(twi_scl),
	.twi_sda(twi_sda),
	.TWI_RST(TWI_RST),
	.TWI_INT(TWI_INT),
	.WR_DAC_SCLK(WR_DAC_SCLK),
	.WR_DAC_DIN(WR_DAC_DIN),
	.WR_DAC1_SYNC(WR_DAC1_SYNC),
	.WR_DAC2_SYNC(WR_DAC2_SYNC),
	.FPGA_RxD(FPGA_RxD),
	.FPGA_TxD(FPGA_TxD),
	.GPS(GPS_r),
	.ext_config(ext_config),
	.in_use(in_use),
	.lb_clk(lb_clk),
	.lb_addr(lb_addr_w),
	.lb_strobe(lb_strobe_w),
	.lb_rd(lb_rd_w),
	.lb_write(lb_write_w),
